#!/usr/bin/env node
/**
 * gen-earthworks-glbs — author one distinct GLB per earthworks kind for the
 * Plan-stage `DesignElementScenegraphLayer` (deck.gl).
 *
 * Phase 4 of ADR `2026-05-11-atlas-deckgl-scenegraph-migration.md`. Earthworks
 * (berms, raised beds, terraces) are low-profile shaped earth — modeled as
 * shallow box/wedge primitives so the silhouette reads as "ground sculpted
 * upward" at typical Plan/Observe pitch.
 *
 * Output GLBs are CC0 — generated by code in this repo. See
 * `public/models/earthworks/NOTICE.md`.
 *
 * Convention: unit-normalized so the base sits at Y=0 and the highest point
 * sits at Y=1. The layer scales each instance to footprintM × heightM ×
 * footprintM.
 *
 * Run via:    pnpm --filter @ogden/web gen:models
 */

import { dirname, join } from 'node:path';
import { fileURLToPath } from 'node:url';
import { writeGLB } from './lib/glb-writer.mjs';
import { box, merge } from './lib/primitives.mjs';

const __dirname = dirname(fileURLToPath(import.meta.url));
const OUT_DIR = join(__dirname, '..', 'public', 'models', 'earthworks');

/**
 * Berm — long low ridge of earth. Modeled as a stack of two boxes whose
 * upper layer is narrower, suggesting a sloped trapezoidal section.
 */
function berm() {
  return merge([
    box(1.0, 0.5, 1.0, 0.0),
    box(0.7, 0.5, 0.7, 0.5),
  ]);
}

/** Raised bed — rectangular planter with thin border ring and infill. */
function raisedBed() {
  return merge([
    // Floor / soil fill
    box(1.0, 0.85, 1.0, 0.0),
    // Border lip at the top
    box(1.0, 0.15, 0.08, 0.85),
    box(1.0, 0.15, 0.08, 0.85),
    box(0.08, 0.15, 1.0, 0.85),
    box(0.08, 0.15, 1.0, 0.85),
  ]);
}

/** Terrace — two stepped levels suggesting a contoured slope. */
function terrace() {
  return merge([
    box(1.0, 0.5, 0.6, 0.0),
    box(1.0, 0.5, 0.4, 0.5),
  ]);
}

const KINDS = {
  berm:        { color: [0.55, 0.42, 0.30], build: berm },
  'raised-bed':{ color: [0.45, 0.32, 0.22], build: raisedBed },
  terrace:     { color: [0.50, 0.38, 0.26], build: terrace },
};

let totalBytes = 0;
let totalKinds = 0;
for (const [kind, spec] of Object.entries(KINDS)) {
  const mesh = spec.build();
  const outPath = join(OUT_DIR, `${kind}.glb`);
  const stats = writeGLB(
    {
      positions: mesh.positions,
      normals: mesh.normals,
      indices: mesh.indices,
      color: spec.color,
      name: kind,
    },
    outPath,
  );
  console.log(
    `wrote ${outPath} (${stats.bytes} bytes, ${stats.vertexCount} verts, ${stats.triangleCount} tris)`,
  );
  totalBytes += stats.bytes;
  totalKinds += 1;
}
console.log(`\n${totalKinds} earthworks kinds, ${totalBytes} bytes total`);
